INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('PERSONA: Creer 3-5 personas detailles (nom, age, job, frustrations, objectifs) guide toute la strategie marketing.', '3-5 personas detailles = guide marketing', 'marketing', 'best_practice', 0.88, 'massive_boost_17', 'system'),
