('AR_VR: Les filtres AR marques sur Instagram/Snapchat generent 5x plus d engagement que les posts classiques.', 'Filtres AR marque IG/Snap = 5x engagement', NULL, 'insight', 0.78, 'massive_boost_19', 'system'),
('METRIQUE: Le DAU/MAU ratio (daily/monthly active users) est le meilleur indicateur de stickiness. > 25% = excellent.', 'DAU/MAU > 25% = excellent stickiness', 'ceo', 'insight', 0.85, 'massive_boost_19', 'system'),
('METRIQUE: Le time-to-value (TTV) est la metrique #1 de l onboarding. Plus il est court, plus la retention est haute.', 'TTV = metrique #1 onboarding. Court = haute retention', 'onboarding', 'insight', 0.90, 'massive_boost_19', 'system'),
('METRIQUE: Le ARPU (Average Revenue Per User) doit croitre mois apres mois grace a l expansion revenue.', 'ARPU doit croitre via expansion revenue', 'ceo', 'insight', 0.85, 'massive_boost_19', 'system'),
('METRIQUE: Le payback period (mois pour recuperer le CAC) doit etre < 12 mois pour un SaaS sain.', 'Payback period < 12 mois SaaS sain', 'ceo', 'best_practice', 0.88, 'massive_boost_19', 'system'),
('METRIQUE: Le gross margin (marge brute) pour un SaaS typique: 70-85%. Les couts serveur doivent etre < 20% du revenu.', 'Gross margin SaaS: 70-85%. Serveur < 20% revenu', 'comptable', 'insight', 0.85, 'massive_boost_19', 'system'),
('TENDANCE_2026: L IA agentique (agents autonomes qui executent des taches complexes) est LA tendance #1 de 2026.', 'IA agentique = tendance #1 2026', 'ceo', 'insight', 0.90, 'massive_boost_19', 'system'),
('TENDANCE_2026: Le social commerce (achat direct depuis les reseaux sociaux) represente 15% du e-commerce en 2026.', 'Social commerce = 15% ecom 2026', NULL, 'insight', 0.82, 'massive_boost_19', 'system'),
('TENDANCE_2026: Les creator economy platforms (outils pour createurs de contenu) est un marche de 250 milliards en 2026.', 'Creator economy = 250 milliards 2026', NULL, 'insight', 0.78, 'massive_boost_19', 'system'),
('TENDANCE_2026: Le zero-party data (donnees volontairement partagees par le client) remplace les cookies tiers disparus.', 'Zero-party data remplace cookies tiers 2026', 'marketing', 'insight', 0.85, 'massive_boost_19', 'system'),
('TENDANCE_2026: L hyper-personnalisation IA (contenu unique par utilisateur) augmente les conversions de 80%.', 'Hyper-personnalisation IA = +80% conversions', 'marketing', 'insight', 0.85, 'massive_boost_19', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('NEGOTIATION: La technique du "mirror" (repeter les 3 derniers mots de l interlocuteur) augmente l empathie et les accords de 30%.', 'Mirror technique = +30% accords (Chris Voss)', 'commercial', 'best_practice', 0.82, 'massive_boost_20', 'system'),
('NEGOTIATION: Le silence strategique apres une offre force l autre partie a parler et souvent a conceder.', 'Silence apres offre = concession adverse', 'commercial', 'best_practice', 0.80, 'massive_boost_20', 'system'),
('NEGOTIATION: Ancrer haut: la premiere offre influence tout le reste de la negociation. Toujours proposer en premier.', 'Ancrer haut = influencer negociation. Proposer en premier', 'commercial', 'best_practice', 0.85, 'massive_boost_20', 'system'),
('NEGOTIATION: Le BATNA (Best Alternative to Negotiated Agreement) doit etre prepare avant toute negociation.', 'BATNA = preparer alternative avant negociation', 'commercial', 'best_practice', 0.85, 'massive_boost_20', 'system'),
('COLD_EMAIL: Le taux de reponse moyen d un cold email B2B: 1-5%. Au-dessus de 10% = excellent.', 'Cold email B2B: 1-5% reponse moyen, >10% = excellent', 'email', 'insight', 0.85, 'massive_boost_20', 'system'),
('COLD_EMAIL: Les cold emails de 50-125 mots ont le meilleur taux de reponse. Court et personalise.', 'Cold email: 50-125 mots optimal', 'email', 'best_practice', 0.85, 'massive_boost_20', 'system'),
('COLD_EMAIL: Le subject line personnalise (prenom ou nom d entreprise) augmente l ouverture de 26%.', 'Subject line personnalise = +26% ouverture', 'email', 'insight', 0.85, 'massive_boost_20', 'system'),
('COLD_EMAIL: Le follow-up #3 a un taux de reponse de 18% (le plus eleve de la sequence). Ne jamais s arreter au 1er email.', 'Follow-up #3 = 18% reponse. Ne pas abandonner', 'email', 'insight', 0.82, 'massive_boost_20', 'system'),
